184→/**
185→ * Updates the streak display with current streak information
186→ * @param {Match3Game} game - The game instance
187→ * @param {HTMLElement} streakDisplay - The streak display element
188→ */
189→function updateStreakDisplay(game, streakDisplay) {
190→    const streak = game.currentStreak;
191→
192→    // Create progress bar with 3 sections
193→    let content = `
194→        <div class="streak-header">
195→            <span class="streak-icon">🔥</span>
196→            <span class="streak-title">${streak === 0 ? "No Streak" : "Streak"}</span>
197→        </div>
198→    `;
199→
200→    if (streak > 0) {
201→        content += `
202→        <div class="streak-progress-container">
203→            <div class="streak-section ${streak >= 1 ? "active" : ""}">
204→                <div class="streak-powerup">${streak >= 1 ? "🔨" : ""}</div>
205→                <div class="streak-bar first"></div>
206→            </div>
207→            <div class="streak-section ${streak >= 2 ? "active" : ""}">
208→                <div class="streak-powerup">${streak >= 2 ? "✂️" : ""}</div>
209→                <div class="streak-bar"></div>
210→            </div>
211→            <div class="streak-section ${streak >= 3 ? "active" : ""}">
212→                <div class="streak-powerup">${streak >= 3 ? "🔄" : ""}</div>
213→                <div class="streak-bar last"></div>
214→            </div>
215→        </div>`;
216→    }
217→
218→    streakDisplay.style.display = "flex";
219→    streakDisplay.innerHTML = content;
220→}
221→
222→/**
223→ * Hides the home screen and shows the game
224→ */
225→export function hideHomeScreen() {
226→    const homeScreen = document.getElementById("home-screen");
227→    const gameContainer = document.getElementById("game-container");
228→
229→    homeScreen.style.display = "none";
230→    gameContainer.style.display = "flex";
231→}
