233→/**
234→ * Updates the hearts display with current hearts and timer
235→ * @param {Match3Game} game - The game instance
236→ * @param {HTMLElement} heartsDisplay - The hearts display element
237→ */
238→export function updateHeartsDisplay(game, heartsDisplay) {
239→    const hearts = game.hearts;
240→    const maxHearts = game.MAX_HEARTS;
241→
242→    // Create heart icons
243→    let heartsHTML = `<div class="hearts-container">
244→        <h2 class="heart-icon${hearts === 0 ? " empty" : ""}">♥️</h2>
245→          <stroked-text
246→            class="heart-count"
247→            text="${hearts}"
248→            font-size="20"
249→            font-weight="900"
250→            stroke-width="7"
251→            width="100"
252→            height="60">
253→          </stroked-text>
254→      </div>
255→    `;
256→
257→    // Add timer or full message
258→    if (hearts >= maxHearts) {
259→        heartsHTML += '<h2 class="hearts-full">Full</h2>';
260→    } else if (hearts < maxHearts) {
261→        const timeRemaining = game.getTimeUntilNextHeart();
262→        const minutes = Math.floor(timeRemaining / (60 * 1000));
263→        const seconds = Math.floor((timeRemaining % (60 * 1000)) / 1000);
264→        const timerText = `${minutes}:${seconds.toString().padStart(2, "0")}`;
265→        heartsHTML += `<h4 class="hearts-timer">${timerText}</h4>`;
266→
267→        // Update timer every second if not at max hearts
268→        clearInterval(game.heartsTimerInterval);
269→        game.heartsTimerInterval = setInterval(() => {
270→            game.regenerateHearts();
271→            if (document.getElementById("home-screen").style.display === "flex") {
272→                updateHeartsDisplay(game, heartsDisplay);
273→            } else {
274→                clearInterval(game.heartsTimerInterval);
275→            }
276→        }, 1000);
277→    }
278→
279→    heartsDisplay.innerHTML = heartsHTML;
280→}
281→
282→/**
283→ * Updates the coins display with current coin count
284→ * @param {Match3Game} game - The game instance
285→ * @param {HTMLElement} coinsDisplay - The coins display element
286→ */
287→function updateCoinsDisplay(game, coinsDisplay) {
288→    const coins = game.coins;
289→    const formattedCoins = coins.toLocaleString();
290→
291→    const coinsHTML = `
292→        <img src="assets/shop/coin.png" class="coin-icon" alt="Coins" />
293→        <div class="coin-count">${formattedCoins}</div>
294→    `;
295→
296→    coinsDisplay.innerHTML = coinsHTML;
297→}
298→
299→/**
300→ * Initializes home screen event listeners
301→ * @param {Match3Game} game - The game instance
302→ */
303→export function initializeHomeScreen(game) {
304→    const levelButton = document.getElementById("start-level-button");
305→    const noHeartsDialog = document.getElementById("noHeartsDialog");
306→    const closeNoHeartsBtn = document.getElementById("closeNoHeartsBtn");
307→    const fillHeartsBtn = document.getElementById("fillHeartsBtn");
308→    const coinsDisplay = document.getElementById("coins-display");
309→    const shopDialog = document.getElementById("shopDialog");
310→    const closeShopBtn = document.getElementById("closeShopBtn");
311→    const shopBuyBtns = document.querySelectorAll(".shop-buy-btn");
312→
313→    levelButton.addEventListener("click", () => {
314→        // Check if player has hearts to play
315→        if (game.hearts <= 0) {
316→            // No hearts available - show dialog
317→            noHeartsDialog.classList.remove("hidden");
318→            return;
319→        }
320→
321→        // Clear hearts timer when starting level
322→        clearInterval(game.heartsTimerInterval);
323→
324→        hideHomeScreen();
325→        game.startLevel();
326→    });
327→
328→    // Fill hearts with coins handler
329→    if (fillHeartsBtn) {
330→        fillHeartsBtn.addEventListener("click", () => {
331→            const HEART_REFILL_COST = 800;
332→
333→            // Check if player has enough coins
334→            if (game.coins >= HEART_REFILL_COST) {
335→                // Deduct coins
336→                game.coins -= HEART_REFILL_COST;
337→                game.saveCoins();
338→
339→                // Fill hearts to max
340→                game.hearts = game.MAX_HEARTS;
341→                saveHearts(game.hearts);
342→
343→                // Update regeneration time
344→                game.lastRegenTime = Date.now();
345→                saveLastRegenTime(game.lastRegenTime);
346→
347→                // Update all displays
348→                const heartsDisplay = document.getElementById("hearts-display");
349→                updateHeartsDisplay(game, heartsDisplay);
350→                updateCoinsDisplay(game, coinsDisplay);
351→
352→                // Close dialog
353→                noHeartsDialog.classList.add("hidden");
354→            } else {
355→                // Not enough coins - open shop instead
356→                shopDialog.classList.remove("hidden");
357→                // Update shop coins display
358→                const shopCoinsDisplay = document.getElementById("shop-coins-display");
359→                if (shopCoinsDisplay) {
360→                    updateCoinsDisplay(game, shopCoinsDisplay);
361→                }
362→            }
363→        });
364→    }
365→
366→    // Close dialog handler
367→    if (closeNoHeartsBtn) {
368→        closeNoHeartsBtn.addEventListener("click", () => {
369→            noHeartsDialog.classList.add("hidden");
370→        });
371→    }
372→
373→    // Shop dialog handlers
374→    if (coinsDisplay) {
375→        coinsDisplay.addEventListener("click", () => {
376→            shopDialog.classList.remove("hidden");
377→            // Update shop coins display when opening
378→            const shopCoinsDisplay = document.getElementById("shop-coins-display");
379→            if (shopCoinsDisplay) {
380→                updateCoinsDisplay(game, shopCoinsDisplay);
381→            }
382→        });
383→    }
384→
385→    if (closeShopBtn) {
386→        closeShopBtn.addEventListener("click", () => {
387→            shopDialog.classList.add("hidden");
388→        });
389→    }
390→
391→    // Close shop when clicking backdrop
392→    if (shopDialog) {
393→        shopDialog.addEventListener("click", (e) => {
394→            if (e.target === shopDialog) {
395→                shopDialog.classList.add("hidden");
396→            }
397→        });
398→    }
399→
400→    // Shop purchase handlers
401→    shopBuyBtns.forEach((btn) => {
402→        // Store original button HTML for restoration
403→        const originalHTML = btn.innerHTML;
404→
405→        btn.addEventListener("click", (e) => {
406→            e.stopPropagation();
407→            const shopItem = btn.closest(".shop-item");
408→            const coinsAmount = parseInt(shopItem.getAttribute("data-coins"));
409→
410→            // Validate coinsAmount
411→            if (isNaN(coinsAmount)) {
412→                return;
413→            }
414→
415→            // Add coins to player's balance
416→            game.coins = Number(game.coins) + Number(coinsAmount);
417→            game.saveCoins();
418→
419→            // Update all coins displays (home, shop, extra moves dialog)
420→            game.updateCoinsDisplays();
421→
422→            // Show purchase feedback
423→            const originalBg = btn.style.background;
424→            btn.textContent = "✓";
425→            btn.style.background = "#8bc34a";
426→            setTimeout(() => {
427→                btn.innerHTML = originalHTML;
428→                btn.style.background = originalBg;
429→            }, 1500);
430→        });
431→    });
432→}
