300→export function createGoalCard(game, goal) {
301→    const goalCard = document.createElement("div");
302→    let isCompleted, currentProgress, goalTypeClass, goalIcon, goalContent;
303→
304→    if (goal.goalType === "current") {
305→        isCompleted = goal.current >= goal.target;
306→        currentProgress = goal.current;
307→        goalTypeClass = "goal-current";
308→        goalIcon = "📍";
309→
310→        const displayValue = getDisplayValue(goal.tileValue);
311→        goalContent = `
312→                <div class="gem tile-${goal.tileValue} goal-tile">
313→                    <span style="font-size: ${getFontSize(displayValue)}cqw">${displayValue}</span>
314→                </div>`;
315→    } else if (goal.goalType === "blocked") {
316→        isCompleted = goal.current >= goal.target;
317→        currentProgress = goal.current;
318→        goalTypeClass = "goal-blocked";
319→        goalIcon = "♻️";
320→        goalContent = `<div class="gem tile-BLOCKED goal-tile"></div>`;
321→    } else if (goal.goalType === "cursed") {
322→        isCompleted = goal.current >= goal.target;
323→        currentProgress = goal.current;
324→        goalTypeClass = "goal-cursed";
325→        goalIcon = goal.implode ? "💥" : "💀";
326→        const displayValue = getDisplayValue(goal.tileValue);
327→        goalContent = `
328→                <div class="gem tile-${goal.tileValue} cursed-tile goal-tile" data-cursed-moves="${goal.strength}">
329→                    <span style="font-size: ${getFontSize(displayValue)}cqw">${displayValue}</span>
330→                </div>`;
331→    } else if (goal.goalType === "score") {
332→        return createScoreGoalCard(goal);
333→    } else {
334→        isCompleted = goal.created >= goal.target;
335→        currentProgress = goal.created;
336→        goalTypeClass = "goal-created";
337→        goalIcon = "⭐";
338→        const displayValue = getDisplayValue(goal.tileValue);
339→        goalContent = `
340→                <div class="gem tile-${goal.tileValue} goal-tile">
341→                    <span style="font-size: ${getFontSize(displayValue)}cqw">${displayValue}</span>
342→                </div>`;
343→    }
344→
345→    goalCard.className = `goal-card ${goalTypeClass} ${isCompleted ? "completed" : ""}`;
346→
347→    const goalProgress = goal.target - currentProgress;
348→    const goalProgressElement = `
349→        <stroked-text
350→            text="${goalProgress}"
351→            font-size="20"
352→            stroke-width="8"
353→            width="100"
354→            height="24"
355→            svg-style="height: 100%;">
356→        </stroked-text>
357→        `;
358→    goalCard.innerHTML = `
359→            ${goalContent}
360→            <div class="goal-icon">${goalIcon}</div>
361→            ${
362→                isCompleted
363→                    ? '<div class="goal-check">✓</div>'
364→                    : `<div class="goal-progress">${goalProgressElement}</div>`
365→            }
366→        `;
367→    return goalCard;
368→}
