 35→export function setupPowerUps(game) {
 36→    const powerUpButtons = document.querySelectorAll(".power-up-btn.game");
 37→
 38→    powerUpButtons.forEach((button) => {
 39→        button.addEventListener("click", () => {
 40→            if (!game.gameActive) return;
 41→
 42→            const powerUpType = button.dataset.powerup;
 43→
 44→            if (!isPowerUpButtonVisible(game, powerUpType)) {
 45→                return;
 46→            }
 47→
 48→            if (isTutorialActive(game) && isTutorialPowerUpStep(game)) {
 49→                if (!isValidTutorialPowerUp(game, powerUpType)) {
 50→                    return;
 51→                }
 52→            }
 53→
 54→            if (game.activePowerUp === powerUpType) {
 55→                deactivatePowerUp(game);
 56→            } else {
 57→                const isBuying = getTotalPowerUpCount(game, powerUpType) <= 0;
 58→                if (isBuying) {
 59→                    if (game.powerUpMoveCost) {
 60→                        if (game.movesUsed >= game.maxMoves) return;
 61→                    } else if (game.coins < getPowerUpCost(powerUpType)) {
 62→                        const shopDialog = document.getElementById("shopDialog");
 63→                        if (shopDialog) {
 64→                            shopDialog.classList.remove("hidden");
 65→                            game.updateCoinsDisplays();
 66→                        }
 67→                        return;
 68→                    }
 69→                }
 70→                activatePowerUp(game, powerUpType, isBuying);
 71→            }
 72→        });
 73→    });
 74→}
