138→export function consumePowerUp(game, type) {
139→    game.powerUpUsedCounts[type]++;
140→
141→    if (game.powerUpBuying) {
142→        if (game.powerUpMoveCost) {
143→            game.movesUsed++;
144→            updateMovesDisplay(game);
145→        } else {
146→            const cost = getPowerUpCost(type);
147→            game.coins = Number(game.coins) - Number(cost);
148→            game.saveCoins();
149→            game.updateCoinsDisplays();
150→        }
151→        incrementBuyCount(type);
152→        game.updatePowerUpButtons();
153→        game.powerUpBuying = false;
154→        return;
155→    }
156→
157→    const counts = game.powerUpCounts[type];
158→    if (counts.transient > 0) {
159→        counts.transient--;
160→    } else if (game.persistentPowerUpsEnabled && counts.persistent > 0) {
161→        counts.persistent--;
162→        savePowerUpCounts({
163→            hammer: game.powerUpCounts.hammer.persistent,
164→            halve: game.powerUpCounts.halve.persistent,
165→            swap: game.powerUpCounts.swap.persistent,
166→            teleport: game.powerUpCounts.teleport.persistent,
167→            wildcard: game.powerUpCounts.wildcard.persistent,
168→        });
169→    }
170→}
