toolUseResult.originalFile:
/* Home Screen Styles */
.home-screen {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    width: 100vw;
    height: 100dvh;
    position: absolute;
    top: 0;
    left: 0;
    z-index: 1000;
    padding: 4vh 0 8vh;
}

.home-content {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: space-between;
    flex: 1;
    font-family: "Nunito", sans-serif;
    position: relative;
}

.home-header {
    display: flex;
    justify-content: center;
    gap: 8px;
    position: relative;
    width: 100%;

    .hearts-display {
        font-family: "Nunito", sans-serif;
        display: flex;
        align-items: center;
        gap: 4px;

        border-radius: 24px;
        border: 3px solid #000;
        background: #141414;
        box-shadow: 0 8px 0 0 rgba(0, 0, 0, 0.25);
        padding: 0px 18px;

        line-height: 3rem;

        .hearts-container {
            display: flex;
            position: relative;
            align-items: center;
            gap: clamp(4px, 1vw, 8px);
            font-size: clamp(24px, 6vw, 38px);
        }

        .hearts-container > * {
            color: white;
            font-family: "Nunito";
            font-weight: 900;
            display: inline-block;
        }

        .heart-count {
            position: absolute;
            left: 50%;
            top: 34%;
            transform: translate(-50%, -50%);
        }

        .heart-icon {
            transition: opacity 0.3s ease;
            margin-right: 2px;
            margin-top: 2px;
        }

        .heart-icon.empty {
            opacity: 0.4;
        }

        .hearts-timer {
            color: #fff;
            font-weight: 800;
            text-shadow: 0 2px 4px rgba(0, 0, 0, 0.5);
        }

        .hearts-full {
            /* font-size: clamp(12px, 3vw, 16px); */
            color: white;
            font-family: "Nunito";
            font-weight: 900;
            text-shadow: 0 2px 4px rgba(0, 0, 0, 0.5);
        }
    }

    /* Coins Display */

    .info-btn {
        background: #141414;
        border: 3px solid #000;
        border-radius: 35%;
        width: 1.6em;
        height: 1.6em;
        display: flex;
        align-items: center;
        justify-content: center;
        cursor: pointer;
        transition: all 0.2s ease;
        font-size: 18px;
        font-family: Nunito;
        font-weight: 900;
        z-index: 10;
        color: rgba(255, 255, 255, 0.8);

        position: absolute;
        top: 50%;
        right: 10px;
        transform: translateY(-50%);
    }
}

.coins-display {
    font-family: "Nunito", sans-serif;
    display: flex;
    align-items: center;
    gap: clamp(6px, 1.5vw, 12px);

    border-radius: 24px;
    border: 3px solid #000;
    background: #141414;
    box-shadow: 0 8px 0 0 rgba(0, 0, 0, 0.25);
    padding: clamp(4px, 1vw, 8px) clamp(12px, 2.5vw, 20px);

    cursor: pointer;

    .coin-icon {
        width: clamp(32px, 7vw, 48px);
        height: clamp(32px, 7vw, 48px);
        object-fit: contain;
    }

    .coin-count {
        color: #fff;
        font-size: clamp(18px, 4vw, 28px);
        font-weight: 900;
        text-shadow: 0 2px 4px rgba(0, 0, 0, 0.5);
    }
}

/* Super Streak Display - Circular Progress */
.super-streak-display {
    display: flex;
    justify-content: center;
    align-items: center;
    margin-bottom: 16px;
}

.super-streak-container {
    position: relative;
    width: 120px;
    height: 120px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.super-streak-circle {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    transform: scaleX(-1);
    overflow: visible;
}

.super-streak-circle .progress-circle {
    transition: stroke-dashoffset 0.6s ease;
}

.super-streak-container.active .super-streak-circle .progress-circle {
    filter: drop-shadow(0 0 8px rgba(218, 34, 255, 0.8));
    animation: pulse-glow 2s ease-in-out infinite;
}

.super-streak-icon {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 52px;
    height: 52px;
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 2;
}

.super-streak-icon img {
    width: 100%;
    height: 100%;
    object-fit: contain;
    filter: drop-shadow(0 2px 4px rgba(0, 0, 0, 0.5));
}

.super-streak-container.active .super-streak-icon img {
    animation: bounce-icon 2s ease-in-out infinite;
}

.super-streak-text {
    position: absolute;
    bottom: -8px;
    left: 50%;
    transform: translateX(-50%);
    font-family: "Nunito", sans-serif;
    font-size: 20px;
    font-weight: 900;
    color: #fff;
    text-shadow: 0 2px 4px rgba(0, 0, 0, 0.8), -2px 0 0 #000, 2px 0 0 #000, 0 -2px 0 #000, 0 2px 0 #000;
    z-index: 3;
}

@keyframes pulse-glow {
    0%,
    100% {
        filter: drop-shadow(0 0 8px rgba(218, 34, 255, 0.8));
    }
    50% {
        filter: drop-shadow(0 0 16px rgba(218, 34, 255, 1));
    }
}

@keyframes bounce-icon {
    0%,
    100% {
        transform: scale(1);
    }
    50% {
        transform: scale(1.1);
    }
}

.streak-display {
    font-family: "Nunito", sans-serif;
    font-size: clamp(18px, 5vw, 32px);
    font-weight: 700;
    color: #fff;
    text-shadow: 0 2px 4px rgba(0, 0, 0, 0.5);
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 8px;

    border-radius: 24px 24px 0 0;
    border: 3px solid #000;
    background: #141414;
    padding: 6px 20px 30px 20px;
    margin-bottom: -24px;
}

.streak-header {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
}

.streak-icon {
    font-size: clamp(24px, 6vw, 32px);
}

.streak-title {
    font-size: clamp(18px, 5vw, 24px);
    font-weight: 700;
    color: #fff;
}

.streak-progress-container {
    width: 100%;
    display: flex;
    align-items: flex-end;
    gap: 3px;
    margin-bottom: 4px;
}

.streak-section {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
}

.streak-powerup {
    font-size: clamp(24px, 6vw, 32px);
    min-height: clamp(28px, 7vw, 36px);
    display: flex;
    align-items: center;
    justify-content: center;
    opacity: 0.3;
    transition: all 0.3s ease;
}

.streak-section.active .streak-powerup {
    opacity: 1;
    animation: pop-in 0.3s ease;
}

.streak-bar {
    width: 100%;
    height: 13px;
    background: rgba(255, 255, 255, 0.1);
    box-shadow: 0 -3px 0 0 rgba(0, 0, 0, 0.25) inset;
    position: relative;
    overflow: hidden;
}

.streak-bar.first {
    border-radius: 6px 0 0 6px;
}
.streak-bar.last {
    border-radius: 0 6px 6px 0;
}

.streak-section.active .streak-bar {
    background: #7ebb39;
}

/* Preview/Locked Streak State */
.streak-header.preview-locked {
    opacity: 0.8;
    position: relative;
}

.streak-lock-icon {
    font-size: clamp(14px, 4vw, 18px);
    margin-left: 4px;
    opacity: 0.7;
}

@keyframes pop-in {
    0% {
        transform: scale(0);
    }
    50% {
        transform: scale(1.2);
    }
    100% {
        transform: scale(1);
    }
}

/* No Hearts Dialog */
.no-hearts-dialog {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0, 0, 0, 0.8);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
}

.no-hearts-dialog.hidden {
    display: none;
}

.no-hearts-content {
    border-radius: 24px;
    border: 3px solid #000;
    background: #141414;
    box-shadow: 0 8px 0 0 rgba(0, 0, 0, 0.25);
    padding: clamp(20px, 5vw, 40px);
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: clamp(12px, 3vw, 20px);
    /* width: clamp(230px, 80%, 250px); */
}

.no-hearts-message {
    font-family: "Nunito", sans-serif;
    font-size: clamp(28px, 7vw, 40px);
    font-weight: 900;
    color: #fff;
    text-align: center;
    margin: 0 20px;
}

.no-hearts-submessage {
    font-family: "Nunito", sans-serif;
    font-size: clamp(16px, 4vw, 20px);
    font-weight: 600;
    color: rgba(255, 255, 255, 0.8);
    /* text-align: center; */
    align-self: flex-start;
}

.no-hearts-buttons {
    display: flex;
    flex-direction: column;
    gap: clamp(8px, 2vw, 12px);
    width: 100%;
}

.fill-hearts-btn {
    font-family: "Nunito", sans-serif;
    font-size: clamp(16px, 4vw, 20px);
    font-weight: 900;
    padding: clamp(10px, 2.5vw, 14px) clamp(20px, 4.5vw, 28px);
    border-radius: 16px;
    border: 2px solid black;
    background: #aee96b;
    box-shadow: 0 -4px 0 0 rgba(0, 0, 0, 0.25) inset;
    color: black;
    cursor: pointer;
    transition: all 0.2s ease;
    display: flex;
    flex-direction: column;
    align-items: center;
}

.fill-hearts-text {
    font-size: clamp(18px, 4.5vw, 24px);
}

.fill-hearts-cost {
    display: flex;
    align-items: center;
    gap: clamp(4px, 1vw, 6px);
    font-size: clamp(16px, 4vw, 20px);
}

.fill-hearts-coin-icon {
    width: clamp(20px, 5vw, 24px);
    height: clamp(20px, 5vw, 24px);
    object-fit: contain;
}

.close-hearts-btn {
    font-family: "Nunito", sans-serif;
    font-size: clamp(18px, 4.5vw, 24px);
    font-weight: 900;
    padding: clamp(8px, 2vw, 12px) clamp(16px, 4vw, 24px);
    border-radius: 16px;
    border: 2px solid black;
    background: #141414;
    box-shadow: 0 -4px 0 0 rgba(0, 0, 0, 0.25) inset;
    color: white;
    cursor: pointer;
    transition: all 0.2s ease;
}
